        module = __import__('ma.btc_usd.%s' % name, fromlist=[name])
        for st in module.strategy:
            if 60 <= st.run_period < 1440:
                scheduler.add_job(st.run, "cron", hour="%s/%s" % (start_time, st.run_period / 60))
            elif st.run_period >= 1440:
                scheduler.add_job(st.run, "cron", day="*/%s" % (st.run_period / 1440), hour=start_time)
            else:
                scheduler.add_job(st.run, "cron", minute="*/%s" % (st.run_period,), hour=start_time)
